rules:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {
    match /{document=**} {
      allow read, write: if false;
    }
    function isSignedIn() {
      return request.auth != null;
    }
    function isOwner(email) {
      return isSignedIn() && request.auth.token.email.lower() == email.lower();
    }
    function isValidUser(data, email) {
      return data.keys().hasAll(['email', 'role', 'createdAt', 'balance'])
          && data.keys().size() == 4
          && data.email is string 
          && data.email.lower() == email.lower()
          && data.role is string 
          && (data.role == 'user' || data.role == 'admin')
          && data.createdAt is string
          && data.balance is number;
    }
    match /users/{email} {
      allow read: if isOwner(email);
      allow create: if isOwner(email) 
                   && isValidUser(request.resource.data, email)
                   && (request.resource.data.role == 'user' || email.lower() == 'achavezsalva@gmail.com');
      allow update: if isOwner(email)
                   && isValidUser(request.resource.data, email)
                   && request.resource.data.role == resource.data.role
                   && request.resource.data.createdAt == resource.data.createdAt;
      allow delete: if false;
    }
  }
}
